#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int gcd3(int a, int b, int c) {
    return gcd(a, gcd(b, c));
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                for (int k = j + 1; k < N; k++) {
                    if (gcd3(arr[i], arr[j], arr[k]) == 1) {
                        count++;
                    }
                }
            }
        }
        printf("%d\n", count);
        free(arr);
    }
    return 0;
}

