import sys

def gcd(a, b):
    if b == 0: return a
    return gcd(b, a % b)

def gcd3(a, b, c):
    return gcd(a, gcd(b, c))

t = int(sys.stdin.readline())
for _ in range(t):
    n = int(sys.stdin.readline())
    arr = list(map(int, sys.stdin.readline().split()))
    count = 0
    for i in range(n):
        for j in range(i + 1, n):
            for k in range(j + 1, n):
                if gcd3(arr[i], arr[j], arr[k]) == 1:
                    count += 1
    print(count)

